import type { DbDriver } from '../types/db.js';

/**
 * Excludes a specific row from the reference count so the caller can ask
 * "is anybody **else** still pointing at this image_path?". Story 130.
 */
export type ImageReferenceExclude =
    | { kind: 'food_item'; id: string }
    | { kind: 'meal'; id: string };

/**
 * Returns true if any row other than the excluded one references `imagePath`
 * via:
 *   - `food_items.image_path`
 *   - `meals.image_path`
 *   - `ai_estimations.image_path`
 *
 * `ai_estimations` always counts — per DLR #125 the original-upload image is
 * preserved as RAG evidence even after the user replaces the `food_items`
 * display image, so the directory must not be deleted while that row points
 * at it.
 *
 * Empty / missing `imagePath` returns `false` — there's nothing to release.
 */
export async function isImagePathReferenced(
    driver: DbDriver,
    imagePath: string | null | undefined,
    exclude?: ImageReferenceExclude,
): Promise<boolean> {
    if (!imagePath) return false;

    const foodExcludeId = exclude?.kind === 'food_item' ? exclude.id : null;
    const mealExcludeId = exclude?.kind === 'meal' ? exclude.id : null;

    const food = await driver.queryOne<{ n: number }>(
        'SELECT 1 AS n FROM food_items WHERE image_path = ? AND (? IS NULL OR id != ?) LIMIT 1',
        [imagePath, foodExcludeId, foodExcludeId],
    );
    if (food) return true;

    const meal = await driver.queryOne<{ n: number }>(
        'SELECT 1 AS n FROM meals WHERE image_path = ? AND (? IS NULL OR id != ?) LIMIT 1',
        [imagePath, mealExcludeId, mealExcludeId],
    );
    if (meal) return true;

    // `ai_estimations` is keyed by food_item_id — there's no separate exclude
    // for it. The AI row preserves the original upload even when the
    // food_items row drops its reference (intentional split in DLR #125).
    const ai = await driver.queryOne<{ n: number }>(
        'SELECT 1 AS n FROM ai_estimations WHERE image_path = ? LIMIT 1',
        [imagePath],
    );
    return ai !== null;
}
