import type { CardioDetails, NewCardioDetails } from '../types/health.js';
import type { DbDriver } from '../types/db.js';
import { NOOP_LOGGER, type RepoLogger } from '../types/logger.js';
import { NotFoundError } from '../api/response-helpers.js';

const CARDIO_COLUMNS = `
    activity_id, distance_m, elevation_gain_m, avg_speed_mps,
    avg_hr, max_hr, gear_name, strava_sport_type,
    created_at, updated_at
`;

function hasAnyMetric(payload: NewCardioDetails): boolean {
    const { activity_id: _ignored, ...metrics } = payload;
    return Object.values(metrics).some((value) => value != null && value !== '');
}

export interface CardioDetailsRepositoryOptions {
    log?: RepoLogger;
}

export function createCardioDetailsRepository(driver: DbDriver, options: CardioDetailsRepositoryOptions = {}) {
    const log = options.log ?? NOOP_LOGGER;
    const repository = {
        async findByActivityId(activityId: string): Promise<CardioDetails | null> {
            log.debug('cardioDetails.findByActivityId', { activityId });
            return driver.queryOne<CardioDetails>(
                `SELECT ${CARDIO_COLUMNS} FROM cardio_details WHERE activity_id = ?`,
                [activityId],
            );
        },

        async getByActivityId(activityId: string): Promise<CardioDetails> {
            log.debug('cardioDetails.getByActivityId', { activityId });
            return driver.queryOne<CardioDetails>(
                `SELECT ${CARDIO_COLUMNS} FROM cardio_details WHERE activity_id = ?`,
                [activityId],
                { notFound: () => new NotFoundError(`Cardio details for activity ${activityId} not found`) },
            );
        },

        /**
         * Upsert keyed by `activity_id`. An all-empty payload deletes any
         * existing row — preserves the "row absent ≠ measured zero" invariant
         * from spike §4.2. Returns the resulting row, or `null` if no row exists
         * after the operation.
         */
        async upsert(payload: NewCardioDetails): Promise<CardioDetails | null> {
            if (!payload.activity_id) throw new Error('activity_id is required');

            if (!hasAnyMetric(payload)) {
                log.debug('cardioDetails.upsert: empty payload, deleting any existing row', { activityId: payload.activity_id });
                await driver.execute(`DELETE FROM cardio_details WHERE activity_id = ?`, payload.activity_id);
                return null;
            }

            log.debug('cardioDetails.upsert', { activityId: payload.activity_id });
            await driver.execute(
                `INSERT INTO cardio_details (
                    activity_id, distance_m, elevation_gain_m, avg_speed_mps,
                    avg_hr, max_hr, gear_name, strava_sport_type
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(activity_id) DO UPDATE SET
                    distance_m        = excluded.distance_m,
                    elevation_gain_m  = excluded.elevation_gain_m,
                    avg_speed_mps     = excluded.avg_speed_mps,
                    avg_hr            = excluded.avg_hr,
                    max_hr            = excluded.max_hr,
                    gear_name         = excluded.gear_name,
                    strava_sport_type = excluded.strava_sport_type,
                    updated_at        = datetime('now')`,
                payload.activity_id,
                payload.distance_m ?? null,
                payload.elevation_gain_m ?? null,
                payload.avg_speed_mps ?? null,
                payload.avg_hr ?? null,
                payload.max_hr ?? null,
                payload.gear_name ?? null,
                payload.strava_sport_type ?? null,
            );
            return repository.getByActivityId(payload.activity_id);
        },

        async delete(activityId: string): Promise<boolean> {
            log.debug('cardioDetails.delete', { activityId });
            const result = await driver.execute(`DELETE FROM cardio_details WHERE activity_id = ?`, activityId);
            return result.changes > 0;
        },
    };

    return repository;
}

export type CardioDetailsRepository = ReturnType<typeof createCardioDetailsRepository>;
