import type { NewWeightEntry, WeightEntry } from '../types/health.js';
import type { DbDriver } from '../types/db.js';
import { NOOP_LOGGER, type RepoLogger } from '../types/logger.js';
import { uuidv7 } from '../utils/uuid.js';
import { NotFoundError } from '../api/response-helpers.js';

const COLUMNS = `id, date, weight_kg, notes, created_at, updated_at`;

export interface WeightEntriesRepositoryOptions {
    log?: RepoLogger;
}

/**
 * Body-weight log (story 170). Deliberately simpler than the consumption
 * repository: no macro snapshot, no default-serving recompute — a weight is
 * just a scalar bucketed by app-local `date`. Many rows per date are allowed;
 * there is no upsert.
 */
export function createWeightEntriesRepository(driver: DbDriver, options: WeightEntriesRepositoryOptions = {}) {
    const log = options.log ?? NOOP_LOGGER;
    const repository = {
        async findById(id: string): Promise<WeightEntry | null> {
            log.debug('weight.findById', { id });
            return driver.queryOne<WeightEntry>(`SELECT ${COLUMNS} FROM weight_entries WHERE id = ?`, [id]);
        },

        async getById(id: string): Promise<WeightEntry> {
            log.debug('weight.getById', { id });
            return driver.queryOne<WeightEntry>(`SELECT ${COLUMNS} FROM weight_entries WHERE id = ?`, [id], {
                notFound: () => new NotFoundError(`Weight entry ${id} not found`),
            });
        },

        async getByDate(date: string): Promise<WeightEntry[]> {
            log.debug('weight.getByDate', { date });
            return driver.query<WeightEntry>(
                `SELECT ${COLUMNS} FROM weight_entries WHERE date = ? ORDER BY created_at`,
                date,
            );
        },

        // Reverse-chronological so the history view shows newest first.
        async getByDateRange(from: string, to: string): Promise<WeightEntry[]> {
            log.debug('weight.getByDateRange', { from, to });
            return driver.query<WeightEntry>(
                `SELECT ${COLUMNS} FROM weight_entries WHERE date >= ? AND date <= ? ORDER BY date DESC, created_at DESC`,
                from,
                to,
            );
        },

        async create(entry: NewWeightEntry): Promise<WeightEntry> {
            const id = uuidv7();
            log.debug('weight.create', { id, date: entry.date });
            await driver.execute(
                `INSERT INTO weight_entries (id, date, weight_kg, notes) VALUES (?, ?, ?, ?)`,
                id,
                entry.date,
                entry.weight_kg,
                entry.notes ?? null,
            );
            return repository.getById(id);
        },

        async update(id: string, updates: Partial<NewWeightEntry>): Promise<WeightEntry> {
            const existing = await repository.getById(id);
            log.debug('weight.update', { id, fields: Object.keys(updates) });

            const fields: string[] = [];
            const values: unknown[] = [];
            const allowed = ['date', 'weight_kg', 'notes'] as const;
            for (const field of allowed) {
                if (updates[field] !== undefined) {
                    fields.push(`${field} = ?`);
                    values.push(updates[field] ?? null);
                }
            }
            if (fields.length === 0) return existing;

            fields.push("updated_at = datetime('now')");
            values.push(id);
            await driver.execute(`UPDATE weight_entries SET ${fields.join(', ')} WHERE id = ?`, ...values);
            return repository.getById(id);
        },

        async delete(id: string): Promise<boolean> {
            const existing = await repository.findById(id);
            if (!existing) return false;
            log.debug('weight.delete', { id });
            await driver.execute('DELETE FROM weight_entries WHERE id = ?', id);
            return true;
        },
    };

    return repository;
}

export type WeightEntriesRepository = ReturnType<typeof createWeightEntriesRepository>;
