import type {
    NewStrengthSet,
    NewWorkoutBlock,
    NewWorkoutSession,
    StrengthSet,
    TemplateBlock,
    TemplateStrengthSet,
    WorkoutBlock,
    WorkoutLogPayload,
    WorkoutLogResult,
    WorkoutSession,
    WorkoutSessionWithDetail,
    WorkoutTemplate,
} from '../types/health.js';
import type { DbDriver } from '../types/db.js';
import { NOOP_LOGGER, type RepoLogger } from '../types/logger.js';
import { uuidv7 } from '../utils/uuid.js';
import { NotFoundError } from '../api/response-helpers.js';

const SESSION_COLUMNS = `activity_id, source_template_id, notes, created_at, updated_at`;
const STRENGTH_SET_COLUMNS = `id, session_id, position, exercise_id, set_index,
    reps, weight_kg, rpe, rest_s, notes`;
const WORKOUT_BLOCK_COLUMNS = `id, session_id, position, parent_label, kind, modality,
    duration_s, distance_m, intensity, avg_hr, notes`;

async function loadSessionChildren(
    driver: DbDriver,
    sessionId: string,
): Promise<{ strength_sets: StrengthSet[]; workout_blocks: WorkoutBlock[] }> {
    const strength_sets = await driver.query<StrengthSet>(
        `SELECT ${STRENGTH_SET_COLUMNS} FROM strength_sets WHERE session_id = ? ORDER BY position ASC`,
        sessionId,
    );
    const workout_blocks = await driver.query<WorkoutBlock>(
        `SELECT ${WORKOUT_BLOCK_COLUMNS} FROM workout_blocks WHERE session_id = ? ORDER BY position ASC`,
        sessionId,
    );
    return { strength_sets, workout_blocks };
}

async function nextStrengthSetPosition(driver: DbDriver, sessionId: string): Promise<number> {
    const row = await driver.queryOne<{ max_pos: number | null }>(
        `SELECT MAX(position) AS max_pos FROM strength_sets WHERE session_id = ?`,
        [sessionId],
    );
    return row?.max_pos == null ? 0 : row.max_pos + 1;
}

async function nextWorkoutBlockPosition(driver: DbDriver, sessionId: string): Promise<number> {
    const row = await driver.queryOne<{ max_pos: number | null }>(
        `SELECT MAX(position) AS max_pos FROM workout_blocks WHERE session_id = ?`,
        [sessionId],
    );
    return row?.max_pos == null ? 0 : row.max_pos + 1;
}

async function nextSetIndex(driver: DbDriver, sessionId: string, exerciseId: string): Promise<number> {
    const row = await driver.queryOne<{ max_idx: number | null }>(
        `SELECT MAX(set_index) AS max_idx FROM strength_sets WHERE session_id = ? AND exercise_id = ?`,
        [sessionId, exerciseId],
    );
    return row?.max_idx == null ? 1 : row.max_idx + 1;
}

export interface WorkoutRepositoryOptions {
    log?: RepoLogger;
}

export function createWorkoutRepository(driver: DbDriver, options: WorkoutRepositoryOptions = {}) {
    const log = options.log ?? NOOP_LOGGER;
    const repository = {
        /**
         * Returns the most recent `strength_sets` for a given exercise, newest
         * first across all sessions. Powers the "previous column" prefill on
         * the strength-logging screen (story 143). Limit caps the result so
         * the UI gets the previous session's sets and nothing more.
         */
        async getRecentStrengthSetsByExercise(exerciseId: string, limit = 5): Promise<StrengthSet[]> {
            log.debug('workouts.getRecentStrengthSetsByExercise', { exerciseId, limit });
            return driver.query<StrengthSet>(
                `SELECT ss.id, ss.session_id, ss.position, ss.exercise_id, ss.set_index,
                        ss.reps, ss.weight_kg, ss.rpe, ss.rest_s, ss.notes
                 FROM strength_sets ss
                 JOIN activities a ON a.id = ss.session_id
                 WHERE ss.exercise_id = ?
                 ORDER BY a.date DESC, ss.position DESC
                 LIMIT ?`,
                exerciseId,
                limit,
            );
        },

        async findById(activityId: string): Promise<WorkoutSessionWithDetail | null> {
            log.debug('workouts.findById', { activityId });
            const session = await driver.queryOne<WorkoutSession>(
                `SELECT ${SESSION_COLUMNS} FROM workout_sessions WHERE activity_id = ?`,
                [activityId],
            );
            if (!session) return null;
            const children = await loadSessionChildren(driver, session.activity_id);
            return { ...session, ...children };
        },

        async getById(activityId: string): Promise<WorkoutSessionWithDetail> {
            log.debug('workouts.getById', { activityId });
            const session = await driver.queryOne<WorkoutSession>(
                `SELECT ${SESSION_COLUMNS} FROM workout_sessions WHERE activity_id = ?`,
                [activityId],
                { notFound: () => new NotFoundError(`Workout session for activity ${activityId} not found`) },
            );
            const children = await loadSessionChildren(driver, session.activity_id);
            return { ...session, ...children };
        },

        async create(payload: NewWorkoutSession): Promise<WorkoutSessionWithDetail> {
            if (!payload.activity_id) throw new Error('activity_id is required');
            log.debug('workouts.create', { activityId: payload.activity_id, sourceTemplateId: payload.source_template_id });
            await driver.execute(
                `INSERT INTO workout_sessions (activity_id, source_template_id, notes) VALUES (?, ?, ?)`,
                payload.activity_id,
                payload.source_template_id ?? null,
                payload.notes ?? null,
            );
            return repository.getById(payload.activity_id);
        },

        async update(
            activityId: string,
            updates: Partial<Pick<NewWorkoutSession, 'source_template_id' | 'notes'>>,
        ): Promise<WorkoutSessionWithDetail> {
            await repository.getById(activityId);
            log.debug('workouts.update', { activityId, fields: Object.keys(updates) });

            const fields: string[] = [];
            const values: unknown[] = [];
            const allowed = ['source_template_id', 'notes'] as const;
            for (const field of allowed) {
                if (updates[field] !== undefined) {
                    fields.push(`${field} = ?`);
                    values.push(updates[field] ?? null);
                }
            }
            if (fields.length > 0) {
                fields.push("updated_at = datetime('now')");
                values.push(activityId);
                await driver.execute(
                    `UPDATE workout_sessions SET ${fields.join(', ')} WHERE activity_id = ?`,
                    ...values,
                );
            }
            return repository.getById(activityId);
        },

        async delete(activityId: string): Promise<boolean> {
            log.debug('workouts.delete', { activityId });
            const result = await driver.execute(`DELETE FROM workout_sessions WHERE activity_id = ?`, activityId);
            return result.changes > 0;
        },

        // --- Strength set sub-resource ---

        async addStrengthSet(payload: NewStrengthSet): Promise<StrengthSet> {
            await repository.getById(payload.session_id);
            const id = uuidv7();
            log.debug('workouts.addStrengthSet', { id, sessionId: payload.session_id, exerciseId: payload.exercise_id });
            await driver.execute(
                `INSERT INTO strength_sets (id, session_id, position, exercise_id, set_index, reps, weight_kg, rpe, rest_s, notes)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                id,
                payload.session_id,
                payload.position,
                payload.exercise_id,
                payload.set_index,
                payload.reps ?? null,
                payload.weight_kg ?? null,
                payload.rpe ?? null,
                payload.rest_s ?? null,
                payload.notes ?? null,
            );
            return driver.queryOne<StrengthSet>(
                `SELECT ${STRENGTH_SET_COLUMNS} FROM strength_sets WHERE id = ?`,
                [id],
                { notFound: () => new Error(`strength_set ${id} missing after insert`) },
            );
        },

        /**
         * Append a strength set to the end of a session; derives `position` and
         * per-exercise `set_index` automatically. Two integers because they
         * mean different things — `position` orders the whole session, while
         * `set_index` is the 1..N within one exercise.
         */
        async appendStrengthSet(
            sessionId: string,
            payload: Omit<NewStrengthSet, 'session_id' | 'position' | 'set_index'>,
        ): Promise<StrengthSet> {
            const position = await nextStrengthSetPosition(driver, sessionId);
            const set_index = await nextSetIndex(driver, sessionId, payload.exercise_id);
            return repository.addStrengthSet({ ...payload, session_id: sessionId, position, set_index });
        },

        async updateStrengthSet(
            id: string,
            updates: Partial<Pick<NewStrengthSet, 'reps' | 'weight_kg' | 'rpe' | 'rest_s' | 'notes' | 'position' | 'set_index'>>,
        ): Promise<StrengthSet> {
            const existing = await driver.queryOne<StrengthSet>(
                `SELECT ${STRENGTH_SET_COLUMNS} FROM strength_sets WHERE id = ?`,
                [id],
                { notFound: () => new NotFoundError(`Strength set ${id} not found`) },
            );
            log.debug('workouts.updateStrengthSet', { id, fields: Object.keys(updates) });

            const fields: string[] = [];
            const values: unknown[] = [];
            const allowed = ['position', 'set_index', 'reps', 'weight_kg', 'rpe', 'rest_s', 'notes'] as const;
            for (const field of allowed) {
                if (updates[field] !== undefined) {
                    fields.push(`${field} = ?`);
                    values.push(updates[field] ?? null);
                }
            }
            if (fields.length === 0) return existing;
            values.push(id);
            await driver.execute(`UPDATE strength_sets SET ${fields.join(', ')} WHERE id = ?`, ...values);
            return driver.queryOne<StrengthSet>(
                `SELECT ${STRENGTH_SET_COLUMNS} FROM strength_sets WHERE id = ?`,
                [id],
                { notFound: () => new Error(`strength_set ${id} disappeared after update`) },
            );
        },

        async deleteStrengthSet(id: string): Promise<boolean> {
            log.debug('workouts.deleteStrengthSet', { id });
            const result = await driver.execute(`DELETE FROM strength_sets WHERE id = ?`, id);
            return result.changes > 0;
        },

        // --- Workout block sub-resource ---

        async addWorkoutBlock(payload: NewWorkoutBlock): Promise<WorkoutBlock> {
            await repository.getById(payload.session_id);
            const id = uuidv7();
            log.debug('workouts.addWorkoutBlock', { id, sessionId: payload.session_id, kind: payload.kind });
            await driver.execute(
                `INSERT INTO workout_blocks (id, session_id, position, parent_label, kind, modality, duration_s, distance_m, intensity, avg_hr, notes)
                 VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                id,
                payload.session_id,
                payload.position,
                payload.parent_label ?? null,
                payload.kind,
                payload.modality ?? null,
                payload.duration_s ?? null,
                payload.distance_m ?? null,
                payload.intensity ?? null,
                payload.avg_hr ?? null,
                payload.notes ?? null,
            );
            return driver.queryOne<WorkoutBlock>(
                `SELECT ${WORKOUT_BLOCK_COLUMNS} FROM workout_blocks WHERE id = ?`,
                [id],
                { notFound: () => new Error(`workout_block ${id} missing after insert`) },
            );
        },

        async appendWorkoutBlock(
            sessionId: string,
            payload: Omit<NewWorkoutBlock, 'session_id' | 'position'>,
        ): Promise<WorkoutBlock> {
            const position = await nextWorkoutBlockPosition(driver, sessionId);
            return repository.addWorkoutBlock({ ...payload, session_id: sessionId, position });
        },

        async updateWorkoutBlock(
            id: string,
            updates: Partial<Omit<NewWorkoutBlock, 'session_id'>>,
        ): Promise<WorkoutBlock> {
            const existing = await driver.queryOne<WorkoutBlock>(
                `SELECT ${WORKOUT_BLOCK_COLUMNS} FROM workout_blocks WHERE id = ?`,
                [id],
                { notFound: () => new NotFoundError(`Workout block ${id} not found`) },
            );
            log.debug('workouts.updateWorkoutBlock', { id, fields: Object.keys(updates) });

            const fields: string[] = [];
            const values: unknown[] = [];
            const allowed = [
                'position', 'parent_label', 'kind', 'modality',
                'duration_s', 'distance_m', 'intensity', 'avg_hr', 'notes',
            ] as const;
            for (const field of allowed) {
                if (updates[field] !== undefined) {
                    fields.push(`${field} = ?`);
                    values.push(updates[field] ?? null);
                }
            }
            if (fields.length === 0) return existing;
            values.push(id);
            await driver.execute(`UPDATE workout_blocks SET ${fields.join(', ')} WHERE id = ?`, ...values);
            return driver.queryOne<WorkoutBlock>(
                `SELECT ${WORKOUT_BLOCK_COLUMNS} FROM workout_blocks WHERE id = ?`,
                [id],
                { notFound: () => new Error(`workout_block ${id} disappeared after update`) },
            );
        },

        async deleteWorkoutBlock(id: string): Promise<boolean> {
            log.debug('workouts.deleteWorkoutBlock', { id });
            const result = await driver.execute(`DELETE FROM workout_blocks WHERE id = ?`, id);
            return result.changes > 0;
        },

        /**
         * Expand a template into a session in one transaction. Snapshots the
         * template's targets as initial actuals, so later edits to the template
         * never rewrite logged sessions — same invariant as
         * `consumption_entries`. Mirrors `meals.logMeal` (design_log #117).
         */
        async logTemplate(templateId: string, payload: WorkoutLogPayload): Promise<WorkoutLogResult> {
            const template = await driver.queryOne<WorkoutTemplate>(
                `SELECT id, name, notes, use_count, last_used_at, archived_at, created_at, updated_at
                 FROM workout_templates WHERE id = ?`,
                [templateId],
                { notFound: () => new NotFoundError(`Workout template ${templateId} not found`) },
            );
            const templateSets = await driver.query<TemplateStrengthSet>(
                `SELECT id, template_id, position, exercise_id, target_set_count,
                        target_reps, target_weight_kg, target_rpe, target_rest_s, notes
                 FROM template_strength_sets WHERE template_id = ? ORDER BY position ASC`,
                templateId,
            );
            const templateBlocks = await driver.query<TemplateBlock>(
                `SELECT id, template_id, position, parent_label, kind, modality,
                        target_duration_s, target_distance_m, target_intensity, notes
                 FROM template_blocks WHERE template_id = ? ORDER BY position ASC`,
                templateId,
            );

            const activityId = uuidv7();
            log.debug('workouts.logTemplate: BEGIN', {
                templateId, activityId, date: payload.date,
                templateSets: templateSets.length, templateBlocks: templateBlocks.length,
            });

            await driver.execute('BEGIN TRANSACTION');
            try {
                await driver.execute(
                    `INSERT INTO activities (id, type, source, title, date)
                     VALUES (?, 'workout', 'manual', ?, ?)`,
                    activityId,
                    payload.title?.trim() || template.name,
                    payload.date,
                );
                await driver.execute(
                    `INSERT INTO workout_sessions (activity_id, source_template_id) VALUES (?, ?)`,
                    activityId,
                    templateId,
                );

                let setPos = 0;
                for (const t of templateSets) {
                    const setCount = Math.max(1, t.target_set_count);
                    for (let i = 1; i <= setCount; i++) {
                        await driver.execute(
                            `INSERT INTO strength_sets (id, session_id, position, exercise_id, set_index, reps, weight_kg, rpe, rest_s, notes)
                             VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                            uuidv7(),
                            activityId,
                            setPos++,
                            t.exercise_id,
                            i,
                            t.target_reps ?? null,
                            t.target_weight_kg ?? null,
                            t.target_rpe ?? null,
                            t.target_rest_s ?? null,
                            t.notes ?? null,
                        );
                    }
                }

                let blockPos = 0;
                for (const b of templateBlocks) {
                    await driver.execute(
                        `INSERT INTO workout_blocks (id, session_id, position, parent_label, kind, modality, duration_s, distance_m, intensity, avg_hr, notes)
                         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                        uuidv7(),
                        activityId,
                        blockPos++,
                        b.parent_label ?? null,
                        b.kind,
                        b.modality ?? null,
                        b.target_duration_s ?? null,
                        b.target_distance_m ?? null,
                        b.target_intensity ?? null,
                        null,
                        b.notes ?? null,
                    );
                }

                await driver.execute(
                    `UPDATE workout_templates
                     SET use_count = use_count + 1, last_used_at = datetime('now'), updated_at = datetime('now')
                     WHERE id = ?`,
                    templateId,
                );
                await driver.execute('COMMIT');
                log.debug('workouts.logTemplate: COMMIT', { templateId, activityId });
            } catch (err) {
                await driver.execute('ROLLBACK');
                log.warn('workouts.logTemplate: ROLLBACK', {
                    templateId, activityId,
                    error: err instanceof Error ? err.message : String(err),
                });
                throw err;
            }

            const session = await repository.getById(activityId);
            return { activity_id: activityId, session };
        },
    };

    return repository;
}

export type WorkoutRepository = ReturnType<typeof createWorkoutRepository>;
