/**
 * Single message-listener bridge between the service worker and the main
 * thread. Story 133 / design_log #135. Dispatches typed `SwMessage`s to
 * caller-supplied handlers, with exhaustiveness enforced by a `never` check
 * — adding a new `SW_MESSAGES` constant without a handler is a compile error.
 *
 * Callers attach a single bridge at app startup; the existing notification-click
 * flow and the new snapshot-refresh flow both route through here. Anything
 * that isn't a recognized `SwMessage` (verified by `isSwMessage`) is ignored
 * silently — could be a stray message from a different SW protocol.
 */

import { isSwMessage, SW_MESSAGES, type SwMessage } from './sw-messages.js';

export interface MessageSource {
    addEventListener(type: 'message', listener: (event: MessageEvent) => void): void;
    removeEventListener(type: 'message', listener: (event: MessageEvent) => void): void;
}

export interface SwMessageHandlers {
    onSnapshotMarkDirty?: () => void;
    onSnapshotRefresh?: () => void;
    onNotificationClick?: (detail: { path: string }) => void;
}

/**
 * Attach a single `message` listener that dispatches incoming `SwMessage`s
 * to the supplied handlers. Returns a disposer that detaches the listener.
 * A null `source` (e.g. `navigator.serviceWorker` unavailable in some test
 * environments) is treated as a no-op.
 */
export function attachSwMessageBridge(
    source: MessageSource | null,
    handlers: SwMessageHandlers,
): () => void {
    if (!source) return () => {};

    const listener = (event: MessageEvent) => {
        if (!isSwMessage(event.data)) return;
        dispatch(event.data, handlers);
    };

    source.addEventListener('message', listener);
    return () => source.removeEventListener('message', listener);
}

/**
 * Exported for direct unit testing of the dispatch logic without a real
 * `MessageEvent` round-trip. Production code goes through `attachSwMessageBridge`.
 */
export function dispatch(msg: SwMessage, handlers: SwMessageHandlers): void {
    switch (msg.action) {
        case SW_MESSAGES.SNAPSHOT_MARK_DIRTY:
            handlers.onSnapshotMarkDirty?.();
            return;
        case SW_MESSAGES.SNAPSHOT_REFRESH:
            handlers.onSnapshotRefresh?.();
            return;
        case SW_MESSAGES.NOTIFICATION_CLICK:
            handlers.onNotificationClick?.(msg.detail);
            return;
        default: {
            // TypeScript exhaustiveness check — if a new SW_MESSAGES action
            // is added without a case here, `msg` will not be `never` and
            // the compiler will fail this line.
            const _exhaustive: never = msg;
            void _exhaustive;
            return;
        }
    }
}
